CREATE TABLE `daily_expenses` (
  `id` varchar(255) NOT NULL COMMENT '日表唯一ID',
  `year` int NOT NULL COMMENT '年份（关联月表）',
  `month` int NOT NULL COMMENT '月份（关联月表）',
  `day` int NOT NULL COMMENT '日期（1-31）',
  `single_expense` decimal(10,2) DEFAULT NULL COMMENT '单次花销金额（0表示无消费）',
  `expense_reason` varchar(50) DEFAULT NULL COMMENT '花销原因（如零食、三餐）',
  `expense_content` varchar(100) DEFAULT NULL COMMENT '花销内容物（如干脆面、猪脚饭）',
  `daily_total` decimal(10,2) DEFAULT NULL COMMENT '当日花销合计',
  `create_by` varchar(255) DEFAULT NULL COMMENT '创建人',
  `create_time` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_by` varchar(255) DEFAULT NULL COMMENT '更新人',
  `update_time` datetime DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  KEY `year` (`year`,`month`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='用户每日花销明细表（含单次消费记录）';
